export type AppStatus =
  | 'draft'
  | 'pendingReview'
  | 'changesRequested'
  | 'approved'
  | 'rejected'
  | 'suspended'
  | 'withdrawn';

export type AppState = 'inactive' | 'active' | 'suspended' | 'deleted';

export interface InstallationContext {
  id: string;
  isEnabled: boolean;
  configuration?: Record<string, unknown>;
}

export interface AppStats {
  averageRating: number;
  reviewCount: number;
  installCount: number;
}

export interface VersionContext {
  activeVersionId?: string;
  activeVersionNumber?: string;
  pendingVersionId?: string;
  pendingVersionNumber?: string;
  pendingVersionStatus?: AppStatus;
  active?: AppVersion;
  pending?: AppVersion;
}

export interface AppDefinition {
  id: string;
  developerId: string;
  developerName: string;
  name: string;
  description: string;
  shortDescription: string;
  iconUrl: string;
  state: AppState;

  version: VersionContext;

  // Integration Configuration
  integrationPoints: IntegrationPoint[];
  healthCheckUrl?: string;

  categories: string[];
  tags: string[];

  stats: AppStats;
  installation?: InstallationContext;
  createdDate: string;
  updatedDate: string;
}

/**
 * Thin list-item shape returned by list endpoints (/me/apps, /marketplace/apps, /developers/{id}/apps).
 * Does not include nested active/pending version objects — uses pendingVersionStatus scalar instead.
 */
export interface AppDefinitionListItem {
  id: string;
  developerId: string;
  developerName: string;
  name: string;
  description: string;
  shortDescription: string;
  iconUrl: string;
  state: AppState;

  version: VersionContext;

  // Integration Configuration
  integrationPoints: IntegrationPoint[];
  healthCheckUrl?: string;

  categories: string[];
  tags: string[];

  stats: AppStats;
  installation?: InstallationContext;
  createdDate: string;
  updatedDate: string;
}

export interface AppSubmissionReview {
  id: string;
  appId: string;
  reviewerId: string;
  status: AppStatus;
  comments: string;
  createdDate: string;
}

export interface IntegrationPoint {
  screenId: 'tripDetails' | 'positionActivityStats' | 'appSidebar';
  requiredPermissions: string[];
  baseUrl: string;
}

export interface AppReview {
  id: string;
  appId: string;
  userId: string;
  userName: string;
  organizationName: string;
  rating: number;
  title: string;
  comment: string;
  developerResponse?: string;
  isVerifiedPurchase: boolean;

  // Community Feedback
  helpfulCount: number;

  createdDate: string;
}

export interface AppVersion {
  id: string;
  appDefinitionId: string;
  version: string;
  bumpType: 'patch' | 'minor' | 'major';
  changelog: string;
  name: string;
  description: string;
  shortDescription: string;
  iconUrl: string;
  developerName: string;
  healthCheckUrl?: string;
  integrationPoints: IntegrationPoint[];
  categories: string[];
  tags: string[];
  status: AppStatus;
  state: AppState;
  createdDate: string;
  updatedDate?: string;
}

export const AVAILABLE_SCREENS = [
  { id: 'tripDetails', name: 'Trip Details Screen' },
  { id: 'positionActivityStats', name: 'Vehicle Activity Screen' },
  { id: 'appSidebar', name: 'App Sidebar' },
];
